parameters.text:
=News item to process
Headline:{{ $json.headline }}
url: {{ $json.url }}
snippet: {{ $json.snippet }}
published_date:{{ $json.published_date }}

parameters.jsCode:
//create json object for each json string
return $input.all().map(item => {
  try {
    const parsedData = JSON.parse(item.json.output);

    return {
      json: parsedData
    };
  } catch (e) {
    return {
      json: { 
        error: "Parse error", 
        raw: item.json.output 
      }
    };
  }
});

// This pulls the news_list to the top level so Split Out can find it easily
const rawData = items[0].json.output[0].content[0].text;

// If the model returned a string instead of an object, we parse it
const newsList = typeof rawData === 'string' ? JSON.parse(rawData).news_list : rawData.news_list;

return newsList.map(item => {
  return { json: item };
});

// merge URLs
const urls = [...new Set(
  items
    .map(item => item.json.url)
    .filter(Boolean)
)];

return [
  {
    json: {
      p_urls: urls
    }
  }
];

